@startuml
title ModuleOpensDirective simplified

skinparam shadowing false
skinparam packageStyle rectangle
skinparam classAttributeIconSize 0
skinparam defaultTextAlignment left

skinparam class {
  BackgroundColor #FFF200
  BorderColor #000000
}

skinparam package {
  BackgroundColor #FFFFFF
  BorderColor #000000
}

package "preadapter" as preadapter {
  package "domain" as domain {
    class "ASTVisitorDebug" as ASTVisitorDebug
  }
}

class "ModuleOpensDirective" as ModuleOpensDirective #FFF200

ASTVisitorDebug ..> ModuleOpensDirective : uses
@enduml
